-- Расширенный, более подробный контент для каждой услуги

UPDATE cms_services SET 
  full_description = 'IT-аутсорсинг — это передача обслуживания компьютерной техники, серверов и сети профессиональной IT-команде. Вместо найма штатного системного администратора вы получаете доступ к команде из 4–6 сертифицированных инженеров с опытом 5–17 лет, и при этом экономите до 40% бюджета по сравнению со штатным сотрудником.

Что мы берём на себя: ежедневное обслуживание компьютеров и оргтехники, настройку и сопровождение программного обеспечения, администрирование серверов и сетевой инфраструктуры, обеспечение информационной безопасности, регулярные резервные копии и контроль их целостности, удалённую и выездную техподдержку пользователей.

С первого дня обслуживания за вашей компанией закрепляется персональный менеджер, который знает архитектуру инфраструктуры, историю обращений и специфику бизнес-процессов. Это позволяет решать инциденты в разы быстрее: удалённое подключение — за 15 минут, выезд на объект — за 30 минут по Саратову. У нас официальный договор, прозрачное SLA, фиксированная стоимость без скрытых платежей и отчётность по выполненным работам каждый месяц.'
WHERE slug = 'it-outsourcing';

UPDATE cms_services SET 
  full_description = 'Сервер — критически важный элемент IT-инфраструктуры компании. Сбой сервера 1С, файлового или почтового сервера может остановить работу всего бизнеса на часы или даже дни. Мы обеспечиваем непрерывную, стабильную работу серверной инфраструктуры на базе Windows Server (2012–2022) и Linux (Ubuntu, Debian, CentOS, RHEL).

Полный спектр работ включает: первоначальную настройку и конфигурирование серверов, виртуализацию (VMware, Hyper-V, Proxmox), настройку Active Directory, файловых служб, серверов 1С, корпоративной почты и баз данных. Внедряем системы мониторинга производительности (Zabbix, Grafana) — отслеживаем нагрузку, температуру дисков, свободное место и скорость работы 24/7.

Особое внимание уделяем резервному копированию: разрабатываем стратегию бэкапов под бизнес-задачи (ежедневные инкрементальные, еженедельные полные, хранение в нескольких локациях), регулярно проверяем восстановление из резервных копий. При возникновении инцидентов дежурный инженер реагирует круглосуточно. Главный инженер сетей нашей команды имеет 17 лет опыта работы с серверной инфраструктурой банков и предприятий.'
WHERE slug = 'server-administration';

UPDATE cms_services SET 
  full_description = 'IT-инфраструктура — это нервная система компании: сервера, сеть, рабочие станции, средства защиты и системы хранения данных. Мы создаём и сопровождаем инфраструктуру, которая работает стабильно, безопасно и масштабируется вместе с бизнесом.

Проектируем сети с нуля: выезжаем на объект, изучаем требования бизнеса, готовим техническое задание и проект. Настраиваем оборудование Mikrotik, Cisco, D-Link, Ubiquiti, HP — выполняем сегментацию сети на VLAN, настраиваем VPN-каналы для удалённых сотрудников и связи между филиалами, организуем гостевые Wi-Fi сети с гранулярным контролем доступа.

В части информационной безопасности: внедряем межсетевые экраны (UTM), системы предотвращения вторжений (IPS), защиту от DDoS, контроль трафика и фильтрацию контента. Обеспечиваем мониторинг здоровья оборудования, оповещения о сбоях, регулярный аудит и оптимизацию. Закладываем в проект запас под масштабирование инфраструктуры в 2–3 раза вперёд.'
WHERE slug = 'it-infrastructure';

UPDATE cms_services SET 
  full_description = 'Системы видеонаблюдения помогают защитить имущество, контролировать рабочие процессы, быстро разбирать спорные ситуации и обеспечивать безопасность сотрудников и клиентов. Реализуем проекты любого масштаба — от 2 до 100+ камер, для офиса, магазина, производства, склада или объекта банка.

Подбираем оборудование точно под задачи: уличные IP-камеры с IP67 и защитой от вандалов, скрытые миниатюрные камеры для офиса, поворотные PTZ для больших площадей, тепловизионные камеры для периметра. Поддерживаем все ведущие бренды: Hikvision, Dahua, RVi, ActiveCam. На объекте устанавливаем сетевые видеорегистраторы (NVR) с архивом до 90 дней, настраиваем удалённый просмотр со смартфона через приложение iVMS, Hik-Connect или Dahua DMSS.

Дополнительно интегрируем видеонаблюдение с системами контроля доступа (СКУД), охранной сигнализацией и аналитикой (распознавание лиц, номеров автомобилей, подсчёт посетителей). Реальный кейс: для отделения Банк ВТБ установили 30 камер с интеграцией в централизованную систему мониторинга за 3 дня монтажных работ. На все работы — официальная гарантия 12 месяцев.'
WHERE slug = 'video-surveillance';

UPDATE cms_services SET 
  full_description = 'ЛВС (локальная вычислительная сеть) и СКС (структурированная кабельная система) — это фундамент всей IT-инфраструктуры. Качественно проложенный кабель прослужит 15–20 лет без проблем, а ошибки в монтаже могут стоить компании регулярных простоев и сбоев.

Мы выполняем полный цикл работ: выезжаем на объект для замеров, проектируем схему сети с учётом будущего масштабирования, готовим спецификацию материалов и оборудования. Монтируем кабельные трассы (короба, лотки, гофрорукав, фальш-полы), прокладываем кабель витой пары категорий Cat5e, Cat6, Cat6a или оптоволокно (одномод/мультимод) — в зависимости от задач и бюджета.

Устанавливаем коммутационные шкафы 19", патч-панели, кабельные органайзеры, информационные розетки. Маркируем каждую линию для удобства обслуживания. После монтажа выполняем тестирование сертифицированным оборудованием Fluke Networks: проверяем длину, затухание, перекрёстные наводки и оформляем протокол по каждой линии. На выходе вы получаете не просто работающую сеть, а полный комплект документации: схемы, протоколы тестирования, паспорт сети. Реальный кейс: для ООО ЛукБелОйл смонтировали сеть на 288 портов, 3 этажа, 6 коммутаторов с резервированием.'
WHERE slug = 'lan-installation';

UPDATE cms_services SET 
  full_description = 'IP-телефония — современный стандарт деловой связи: звонки идут через интернет, что экономит до 60% затрат на телефонию по сравнению с традиционными аналоговыми линиями. Помимо экономии вы получаете мощный функционал: многоканальные номера, голосовое меню (IVR), запись и расшифровку разговоров, статистику звонков, переадресацию по сценариям.

Внедряем решения на базе FreePBX (open-source, полный контроль) или облачные виртуальные АТС (без необходимости держать оборудование на объекте). Настраиваем многоканальные городские и федеральные номера 8-800, организуем многоуровневое голосовое меню для распределения звонков по отделам, внедряем сценарии маршрутизации (например, перевод VIP-клиентов на персонального менеджера).

Интегрируем телефонию с CRM-системами: amoCRM, Битрикс24, RetailCRM, Yclients — менеджеры видят карточку клиента ещё до ответа на звонок, разговор автоматически записывается в карточке сделки. Подключаем IP-телефоны (Yealink, Grandstream, Snom) или софтфоны на компьютере и смартфоне. Особое внимание — безопасности: защищаем SIP от взлома, шифруем разговоры, контролируем доступ. Помогаем перенести существующие номера от текущего оператора без потери для клиентов.'
WHERE slug = 'ip-telephony';

-- Дополним FAQ для услуг где меньше 3 пунктов
INSERT INTO cms_service_faq (service_id, sort_order, question, answer) 
SELECT id, 3, 'Какие серверы вы поддерживаете?', 'Windows Server (2012–2022), Linux (Ubuntu, Debian, CentOS, RHEL), виртуализация (VMware, Hyper-V, Proxmox), 1С-серверы, файловые серверы, контроллеры домена Active Directory, корпоративная почта, базы данных PostgreSQL, MS SQL, MySQL.' 
FROM cms_services WHERE slug = 'server-administration' AND NOT EXISTS (SELECT 1 FROM cms_service_faq WHERE service_id = cms_services.id AND sort_order = 3)

UNION ALL SELECT id, 4, 'Что входит в мониторинг 24/7?', 'Отслеживание загрузки CPU, памяти, дискового пространства, температуры, состояния RAID, времени отклика сервисов. При превышении пороговых значений дежурный инженер получает уведомление и оперативно реагирует.' 
FROM cms_services WHERE slug = 'server-administration' AND NOT EXISTS (SELECT 1 FROM cms_service_faq WHERE service_id = cms_services.id AND sort_order = 4)

UNION ALL SELECT id, 3, 'Какое оборудование используете?', 'Mikrotik, Cisco, D-Link, Ubiquiti, HP, MikroTik — выбираем под бюджет и задачи. Можем работать с уже имеющимся оборудованием или подобрать новое с расчётом масштабирования на 2–3 года вперёд.' 
FROM cms_services WHERE slug = 'it-infrastructure' AND NOT EXISTS (SELECT 1 FROM cms_service_faq WHERE service_id = cms_services.id AND sort_order = 3)

UNION ALL SELECT id, 4, 'Можно ли поэтапно внедрять?', 'Да, мы можем разбить проект на этапы: сначала навести порядок в существующей сети, затем модернизировать узкие места, далее внедрить новые сервисы. Подход согласовывается на этапе аудита.' 
FROM cms_services WHERE slug = 'it-infrastructure' AND NOT EXISTS (SELECT 1 FROM cms_service_faq WHERE service_id = cms_services.id AND sort_order = 4)

UNION ALL SELECT id, 4, 'Гарантия на оборудование?', 'Заводская гарантия от производителя — обычно 1–3 года. На монтажные работы предоставляем собственную гарантию 12 месяцев с бесплатным выездом для устранения недостатков.' 
FROM cms_services WHERE slug = 'video-surveillance' AND NOT EXISTS (SELECT 1 FROM cms_service_faq WHERE service_id = cms_services.id AND sort_order = 4)

UNION ALL SELECT id, 3, 'Можно ли подключить новые рабочие места к старой сети?', 'Да, если категория кабеля и состояние сети позволяют. Сначала проводим тестирование существующих линий, при необходимости заменяем повреждённые участки.' 
FROM cms_services WHERE slug = 'lan-installation' AND NOT EXISTS (SELECT 1 FROM cms_service_faq WHERE service_id = cms_services.id AND sort_order = 3)

UNION ALL SELECT id, 4, 'Сколько занимает монтаж?', 'Зависит от объёма. Офис на 20 портов — 1–2 дня. Этаж с 50–80 портами — 3–5 дней. Большие проекты до 300+ портов — 2–4 недели с учётом проектирования и согласований.' 
FROM cms_services WHERE slug = 'lan-installation' AND NOT EXISTS (SELECT 1 FROM cms_service_faq WHERE service_id = cms_services.id AND sort_order = 4)

UNION ALL SELECT id, 3, 'Сохранятся ли текущие номера?', 'Да, в большинстве случаев — через процедуру портирования номеров. Помогаем перевести городские, мобильные и федеральные 8-800 номера к выбранному IP-оператору без потерь для клиентов.' 
FROM cms_services WHERE slug = 'ip-telephony' AND NOT EXISTS (SELECT 1 FROM cms_service_faq WHERE service_id = cms_services.id AND sort_order = 3)

UNION ALL SELECT id, 4, 'Что лучше — FreePBX или ВАТС?', 'FreePBX — полный контроль, разовая оплата, требует своего сервера. ВАТС (виртуальная АТС у оператора) — абонентская плата, не нужно оборудование, быстрый запуск. Подбираем под ваши задачи на консультации.' 
FROM cms_services WHERE slug = 'ip-telephony' AND NOT EXISTS (SELECT 1 FROM cms_service_faq WHERE service_id = cms_services.id AND sort_order = 4);

-- Добавим 4-й пункт FAQ для IT-аутсорсинга
INSERT INTO cms_service_faq (service_id, sort_order, question, answer) 
SELECT id, 4, 'Можно ли перейти с другого подрядчика?', 'Да, у нас отлажен процесс перехода. Запрашиваем у предыдущего подрядчика техническую документацию, проводим аудит инфраструктуры, фиксируем точку входа и принимаем обслуживание без простоя для бизнеса.'
FROM cms_services WHERE slug = 'it-outsourcing' AND NOT EXISTS (SELECT 1 FROM cms_service_faq WHERE service_id = cms_services.id AND sort_order = 4);
